// ВСТАВЬ СВОЙ API КЛЮЧ:
const ANTHROPIC_API_KEY = 'PASTE_YOUR_KEY_HERE';

const body = $input.first().json.body || $input.first().json;
const title = body.title || '';
const description = body.description || '';

const prompt = 'You are a senior full-stack developer. Create a COMPLETE working Next.js 14 SaaS project for this idea.\n\nIdea: ' + title + '\nDescription: ' + description + '\n\nReturn ONLY a JSON object (no markdown, no explanation) with this exact structure:\n{\n  "productName": "Short product name",\n  "tagline": "One compelling line",\n  "problem": "Problem in 2 sentences",\n  "solution": "Solution in 2 sentences",\n  "targetAudience": "Specific target audience",\n  "domain": "suggested-domain.com",\n  "pricing": [{"plan": "Starter", "price": "$29/mo", "features": ["Feature 1", "Feature 2", "Feature 3"]}, {"plan": "Pro", "price": "$79/mo", "features": ["Feature 1", "Feature 2", "Feature 3", "Feature 4"]}],\n  "files": [\n    {"path": "package.json", "content": "complete package.json with next, react, tailwindcss, typescript deps"},\n    {"path": "next.config.ts", "content": "complete next.config.ts"},\n    {"path": "tailwind.config.ts", "content": "complete tailwind config with dark theme"},\n    {"path": "app/globals.css", "content": "globals with tailwind directives and dark variables"},\n    {"path": "app/layout.tsx", "content": "root layout with metadata and dark theme"},\n    {"path": "app/page.tsx", "content": "FULL beautiful dark landing page (#0a0a0a bg, white text) with: hero section with big headline + CTA button, problem section, features grid (6 features), pricing cards (2 tiers), footer. Use Tailwind only, no external libs."},\n    {"path": "app/dashboard/page.tsx", "content": "Dashboard page with sidebar, stats cards, recent activity table. Mock data inline."},\n    {"path": "app/dashboard/layout.tsx", "content": "Dashboard layout with sidebar navigation"},\n    {"path": "README.md", "content": "# ProductName\\n\\nTagline\\n\\n## Quick Start\\n\\n```bash\\nnpm install\\nnpm run dev\\n```\\n\\nOpen http://localhost:3000\\n\\n## Features\\n\\n- Feature list\\n\\n## Tech Stack\\n\\n- Next.js 14 App Router\\n- TypeScript\\n- Tailwind CSS\\n- Stripe (add later)\\n"}\n  ]\n}\n\nIMPORTANT: Every file must have COMPLETE, RUNNABLE code. No TODOs, no placeholders, no "// add your code here". The app must work with just npm install && npm run dev.';

const bodyStr = JSON.stringify({
  model: 'claude-haiku-4-5-20251001',
  max_tokens: 8000,
  messages: [{ role: 'user', content: prompt }]
});

const result = await new Promise((resolve, reject) => {
  const https = require('https');
  const req = https.request({
    hostname: 'api.anthropic.com',
    path: '/v1/messages',
    method: 'POST',
    headers: {
      'x-api-key': ANTHROPIC_API_KEY,
      'anthropic-version': '2023-06-01',
      'content-type': 'application/json',
      'content-length': Buffer.byteLength(bodyStr)
    }
  }, res => {
    let d = '';
    res.on('data', c => d += c);
    res.on('end', () => resolve({ status: res.statusCode, body: d }));
  });
  req.on('error', reject);
  req.write(bodyStr);
  req.end();
});

if (result.status !== 200) throw new Error('Anthropic error ' + result.status + ': ' + result.body);

const data = JSON.parse(result.body);
let product = null;

if (data.content && data.content[0] && data.content[0].text) {
  const text = data.content[0].text.trim();
  const match = text.match(/\{[\s\S]*\}/);
  if (match) {
    try { product = JSON.parse(match[0]); } catch(e) {
      throw new Error('JSON parse failed: ' + e.message + '\n\nRaw: ' + text.slice(0, 500));
    }
  }
}

if (!product) throw new Error('Could not parse product from Claude response');

return [{
  json: {
    ...product,
    ideaId: body.ideaId,
    ideaTitle: title,
    generatedAt: new Date().toISOString()
  }
}];

const fs = require('fs');
const path = require('path');
const product = $input.first().json;

if (product.error) return [{ json: product }];

const slug = (product.productName || 'product').toLowerCase().replace(/[^a-z0-9]/g, '-').replace(/-+/g, '-');
const projectDir = 'C:/autonomy-launches/' + slug;

// Create project directory
if (!fs.existsSync(projectDir)) fs.mkdirSync(projectDir, { recursive: true });

// Save all generated code files
const savedFiles = [];
if (product.files && Array.isArray(product.files)) {
  for (const file of product.files) {
    const filePath = path.join(projectDir, file.path);
    const fileDir = path.dirname(filePath);
    if (!fs.existsSync(fileDir)) fs.mkdirSync(fileDir, { recursive: true });
    fs.writeFileSync(filePath, file.content, 'utf8');
    savedFiles.push(file.path);
  }
}

// Also save landing page as index.html (for quick preview)
if (product.landingPageHtml) {
  fs.writeFileSync(path.join(projectDir, 'index.html'), product.landingPageHtml, 'utf8');
  savedFiles.push('index.html');
} else {
  // Extract landing from files if app/page.tsx exists
  const pageTsx = product.files && product.files.find(f => f.path === 'app/page.tsx');
  if (pageTsx) {
    // Save a quick-open HTML hint
    const hint = '<!DOCTYPE html><html><body style="font-family:sans-serif;padding:2rem;background:#0a0a0a;color:white"><h1>' + product.productName + '</h1><p>' + product.tagline + '</p><hr><p>Чтобы запустить проект:<br><code style="background:#1a1a1a;padding:0.5rem 1rem;border-radius:4px;display:block;margin:1rem 0">cd ' + projectDir.replace(/\//g, '\\') + '<br>npm install<br>npm run dev</code></p><p>Затем открой <a href="http://localhost:3000" style="color:#60a5fa">http://localhost:3000</a></p></body></html>';
    fs.writeFileSync(path.join(projectDir, 'index.html'), hint, 'utf8');
  }
}

// Save brief
const brief = { ...product };
delete brief.files;
delete brief.landingPageHtml;
fs.writeFileSync(path.join(projectDir, 'brief.json'), JSON.stringify(brief, null, 2), 'utf8');

// Update registry
if (!fs.existsSync('C:/autonomy-data')) fs.mkdirSync('C:/autonomy-data', { recursive: true });
const registryPath = 'C:/autonomy-data/launches.json';
let launches = [];
try { launches = JSON.parse(fs.readFileSync(registryPath, 'utf8')); } catch(e) {}

launches.push({
  id: Date.now(),
  ideaId: product.ideaId,
  ideaTitle: product.ideaTitle,
  productName: product.productName,
  tagline: product.tagline,
  slug,
  domain: product.domain,
  status: 'generated',
  projectDir,
  savedFiles,
  generatedAt: product.generatedAt
});
fs.writeFileSync(registryPath, JSON.stringify(launches, null, 2), 'utf8');

return [{
  json: {
    success: true,
    productName: product.productName,
    tagline: product.tagline,
    slug,
    projectDir,
    domain: product.domain,
    savedFiles,
    filesCount: savedFiles.length,
    generatedAt: product.generatedAt
  }
}];
